def parse_tool_payload(text):
    import json
    try:
        obj = json.loads(text)
    except json.JSONDecodeError as e:
        raise ValueError(f"invalid JSON: {e}")
    if "tool" not in obj or "args" not in obj:
        raise ValueError("missing 'tool' or 'args'")
    return obj
